(function(){"use strict";function u(n,e,a){const o=[];for(let t=0;t<a;t++){let s=0;for(let c=0;c<e;c++){const h=Math.floor(Math.random()*n.length);s+=n[h]}o.push(s)}o.sort((t,s)=>t-s);const r=t=>o[Math.floor(t/100*o.length)],i={};o.forEach(t=>{i[t]=(i[t]||0)+1});const l=Object.entries(i).map(([t,s])=>({value:Number(t),count:s}));return{distribution:o,summary:{p50:r(50),p85:r(85),p95:r(95)},histogram:l}}onmessage=function(n){const{dailyCounts:e,horizonDays:a,trials:o}=n.data,r=u(e,a,o);postMessage(r)}})();
